@mixin tooltip--content($tooltip-type: 'icon') {
  @include box-shadow;

  z-index: z('floating');
  @if $tooltip-type == 'definition' {
    padding: $spacing-03 $spacing-05;
  } @else {
    padding: convert.to-rem(3px) $spacing-05;
  }

  border-radius: convert.to-rem(2px);
  background-color: $background-inverse;
  block-size: auto;
  color: $text-inverse;
  font-weight: 400;
  inline-size: max-content;
  max-inline-size: convert.to-rem(208px);
  min-inline-size: convert.to-rem(24px);
  text-align: start;
  transform: translateX(-50%);
  @include type.type-style('body-compact-01');

  // IE media query
  @media all and (-ms-high-contrast: none), (-ms-high-contrast: active) {
    inline-size: auto;
  }
  // Edge 12-15 and Edge 16 feature queries
  @supports (-ms-accelerator: true) {
    inline-size: auto;
  }
  @supports (-ms-ime-align: auto) {
    inline-size: auto;
  }

  // Windows, Firefox HCM Fix
  @media screen and (-ms-high-contrast: active), screen and (prefers-contrast) {
    border: 1px solid transparent;
  }
}

&::before {
  @if ($position == 'top') {
    border-width: convert.to-rem(5px)
      convert.to-rem(4px)
      0
      convert.to-rem(4px);
    border-color: $background-inverse transparent transparent transparent;
    inset-block-start: -$caret-spacing;
    transform: translate(-50%, -100%);
  }
  @if ($position == 'right') {
    border-width: convert.to-rem(4px)
      convert.to-rem(5px)
      convert.to-rem(4px)
      0;
    border-color: transparent $background-inverse transparent transparent;
    inset-inline-end: -$caret-spacing;
    transform: translate(100%, -50%);
  }
  @if ($position == 'bottom') {
    border-width: 0 convert.to-rem(4px) convert.to-rem(5px);
    border-color: transparent transparent $background-inverse;
    inset-block-end: -$caret-spacing;
    transform: translate(-50%, 100%);
  }
  @if ($position == 'left') {
    border-width: convert.to-rem(4px)
      0
      convert.to-rem(4px)
      convert.to-rem(5px);
    border-color: transparent transparent transparent $background-inverse;
    inset-inline-start: -$caret-spacing;
    transform: translate(-100%, -50%);
  }
}

&::after,
  .#{$prefix}--assistive-text,
  + .#{$prefix}--assistive-text {
    @if ($position == 'top') {
      inset-block-start: -$body-spacing;
      @if ($align == 'start') {
        inset-inline-start: 0;
        transform: translate(0, -100%);
      } @else if ($align == 'end') {
        inset-inline: auto 0;
        transform: translate(0, -100%);
      } @else {
        inset-inline-start: 50%;
        transform: translate(-50%, -100%);
      }
    }
    @if ($position == 'right') {
      inset-inline-end: -$body-spacing;
      transform: translate(100%, -50%);
    }
    @if ($position == 'bottom') {
      inset-block-end: -$body-spacing;
      @if ($align == 'start') {
        inset-inline-start: 0;
        transform: translate(0, 100%);
      } @else if ($align == 'end') {
        inset-inline: auto 0;
        transform: translate(0, 100%);
      } @else {
        transform: translate(-50%, 100%);
      }
    }
    @if ($position == 'left') {
      inset-inline-start: -$body-spacing;
      transform: translate(-100%, -50%);
    }
  }

@else {
  // Get our gutters if applicable
  $gutter: -zf-get-bp-val($gutters, $breakpoint);

  // If we have a gutter, add it to the width/height
  @if $gutter {
    @if $vertical == true {
      $unit: if($nested == true, 100%, 100vh);
      $gutter: rem-calc($gutter);
      // Make sure that 0 is translated in 0rem for calc()
      @if $gutter == 0 {
        // sass-lint:disable zero-unit
        $gutter: 0rem;
      }
      height: calc(#{$unit} + #{$gutter});
    } @else {
      $unit: if($nested == true, 100%, 100vw);
      $gutter: rem-calc($gutter);
      // Make sure that 0 is translated in 0rem for calc()
      @if $gutter == 0 {
        // sass-lint:disable zero-unit
        $gutter: 0rem;
      }
      width: calc(#{$unit} + #{$gutter});
    }
  }
  @else {
    @if $vertical == true {
      height: if($nested == true, 100%, 100vh);
    } @else {
      width: if($nested == true, 100%, 100vw);
    }
  }
}

@else {
  &[data-exiting] .#{$prefix}--modal-container {
    animation: #{$prefix}--presence-modal-container__exit
      $duration-moderate-02
      motion(exit, expressive)
      forwards;

    @media screen and (prefers-reduced-motion: reduce) {
      animation: none;
    }
  }

  .#{$prefix}--modal-container {
    animation: #{$prefix}--presence-modal-container__enter
      $duration-moderate-02
      motion(entrance, expressive)
      forwards;

    @media screen and (prefers-reduced-motion: reduce) {
      animation: none;
    }
  }

  @keyframes #{$prefix}--presence-modal-container__enter {
    from {
      transform: translate3d(0, -24px, 0);
    }

    to {
      transform: translate3d(0, 0, 0);
    }
  }

  @keyframes #{$prefix}--presence-modal-container__exit {
    from {
      transform: translate3d(0, 0, 0);
    }

    to {
      transform: translate3d(0, -24px, 0);
    }
  }
}

&:focus {
  z-index: 20;
  display: grid;
  width: auto;
  height: auto;
  min-height: var(--control-medium-size, 32px);
  padding: 0 var(--control-medium-paddingInline-spacious, 16px);
  overflow: auto;
  color: var(--fgColor-onEmphasis, var(--color-fg-on-emphasis));
  background: var(--bgColor-accent-emphasis, var(--color-accent-emphasis));
  border-radius: var(--borderRadius-full, 100vh);
  align-items: center;

  @media (pointer: coarse) {
    &::after {
      @include minTouchTarget(var(--control-minTarget-coarse, 44px));
    }
  }

  @media (prefers-reduced-motion: no-preference) {
    animation: AppFrame-a11yLink-focus 200ms ease-out;
  }

  @keyframes AppFrame-a11yLink-focus {
    0% {
      color: var(--fgColor-accent, var(--color-accent-emphasis));
      transform: scale(0.3, 0.25);
    }

    50% {
      color: var(--fgColor-accent, var(--color-accent-emphasis));
      transform: scale(1, 1);
    }

    55% {
      color: var(--fgColor-onEmphasis, var(--color-fg-on-emphasis));
    }

    100% {
      transform: scaleX(1);
    }
  }
}

@mixin double-caret($background: var(--bgColor-default, var(--color-canvas-default)), $border: var(--borderColor-default, var(--color-border-default))) {
  // stylelint-disable nesting-selector-no-missing-scoping-root
  &::after,
  &::before {
    position: absolute;
    // stylelint-disable-next-line primer/spacing
    top: 11px;
    right: 100%;
    left: calc(var(--base-size-8) * -1);
    display: block;
    width: 8px;
    height: 16px;
    pointer-events: none;
    content: ' ';
    clip-path: polygon(0 50%, 100% 0, 100% 100%);
  }

  &::after {
    // stylelint-disable-next-line primer/spacing
    margin-left: 2px;
    background-color: var(--bgColor-default, var(--color-canvas-default));
    background-image: linear-gradient($background, $background);
  }

  &::before {
    // stylelint-disable-next-line primer/colors
    background-color: $border;
  }
  // stylelint-enable nesting-selector-no-missing-scoping-root
}

@mixin tab-notification-pulsing-animation() {
  @keyframes error-pulse {

    0% {
      background-color: var(--slds-g-color-error-base-40, #{$color-background-destructive});
    }


    40% {
      background-color: var(--slds-g-color-error-base-30, #{$color-background-destructive-active});
    }

    100% {
      background-color: var(--slds-g-color-error-base-40, #{$color-background-destructive});
    }
  }

  @keyframes success-pulse {

    0% {
      background-color: var(--slds-g-color-success-base-50, #{$color-background-success-dark});
    }


    40% {
      background-color: var(--slds-g-color-success-base-40, #{$color-background-success-darker});
    }

    100% {
      background-color: var(--slds-g-color-success-base-50, #{$color-background-success-dark});
    }
  }

  @keyframes warning-pulse {

    0% {
      background-color: var(--slds-g-color-warning-base-60, #{$color-background-warning});
    }


    40% {
      background-color: var(--slds-g-color-warning-base-60, #{$color-background-warning-dark});
    }

    100% {
      background-color: var(--slds-g-color-warning-base-60, #{$color-background-warning});
    }
  }
}

@mixin fluid-multiselect {
  .#{$prefix}--multi-select__wrapper.#{$prefix}--list-box__wrapper--fluid--focus:not(
      .#{$prefix}--multi-select--filterable__wrapper
    )
    .#{$prefix}--list-box__field--wrapper--input-focused {
    outline: none;
  }

  .#{$prefix}--list-box__wrapper--fluid
    .#{$prefix}--tag.#{$prefix}--tag--filter {
    margin-block-start: 1.25rem;
  }

  // Filterable
  .#{$prefix}--list-box__wrapper--fluid
    .#{$prefix}--multi-select--filterable
    .#{$prefix}--list-box__field
    .#{$prefix}--text-input {
    border-block-end: 1px solid transparent;
  }

  .#{$prefix}--list-box__wrapper--fluid
    .#{$prefix}--multi-select--filterable.#{$prefix}--combo-box
    .#{$prefix}--list-box__field {
    align-items: baseline;
  }

  .#{$prefix}--list-box__wrapper--fluid.#{$prefix}--multi-select--filterable__wrapper:not(
      .#{$prefix}--list-box--up
    )
    .#{$prefix}--list-box__menu {
    inset-block-start: calc(100% + convert.to-rem(1px));
  }
}

@each $step, $value in $steps {
  .#{$prefix}--layout--#{$group}-#{$step} {
    @include custom-property.declaration(
      'layout-#{$group}-#{$property}-context',
      custom-property.get-var(
        'layout-#{$group}-#{$property}-#{$step}',
        $value
      )
    );
    @include custom-property.declaration(
      'layout-#{$group}-#{$property}',
      custom-property.get-var('layout-#{$group}-#{$property}-context')
    );
  }

  .#{$prefix}--layout-constraint--#{$group}__default-#{$step} {
    @include custom-property.declaration(
      'layout-#{$group}-#{$property}',
      custom-property.get-var(
        'layout-#{$group}-#{$property}-context',
        custom-property.get-var(
          'layout-#{$group}-#{$property}-#{$step}',
          $value
        )
      )
    );
  }

  @each $constraint in ('min', 'max') {
    .#{$prefix}--layout-constraint--#{$group}__#{$constraint}-#{$step} {
      @include custom-property.declaration(
        'layout-#{$group}-#{$property}-#{$constraint}',
        custom-property.get-var(
          'layout-#{$group}-#{$property}-#{$step}',
          $value
        )
      );
    }
  }
}

@each $key, $value in $cols {
  @for $i from 1 through $value {
    :host(#{$grid-component}) ::slotted(#{$prefix}-column[#{$key}='#{$i}']),
    :host(#{$grid-component})
      ::slotted(#{$prefix}-column[#{$key}*='span:#{$i}']) {
      @extend .#{$prefix}--#{$key}\:col-span-#{$i};
    }

    :host(#{$grid-component})
      ::slotted(#{$prefix}-column[#{$key}*='start:#{$i}']) {
      @extend .#{$prefix}--#{$key}\:col-start-#{$i};
    }

    :host(#{$grid-component})
      ::slotted(#{$prefix}-column[#{$key}*='end:#{$i + 1}']) {
      @extend .#{$prefix}--#{$key}\:col-end-#{$i + 1};
    }

    // span 0
    :host(#{$grid-component}) ::slotted(#{$prefix}-column[#{$key}='0']),
    :host(#{$grid-component})
      ::slotted(#{$prefix}-column[#{$key}*='span:0']) {
      @extend .#{$prefix}--#{$key}\:col-span-0;
    }

    // percent after others otherwise span:2 beats span:25%
    @for $p from 1 through 4 {
      $percent: $p * 25;

      :host(#{$grid-component})
        ::slotted(#{$prefix}-column[#{$key}='#{$percent}%']),
      :host(#{$grid-component})
        ::slotted(#{$prefix}-column[#{$key}*='span:#{$percent}%']) {
        @extend .#{$prefix}--#{$key}\:col-span-#{$percent};
      }
    }
  }
}

@for $i from 1 through $value {
  :host(#{$grid-component}) ::slotted(#{$prefix}-column[#{$key}='#{$i}']),
  :host(#{$grid-component})
    ::slotted(#{$prefix}-column[#{$key}*='span:#{$i}']) {
    @extend .#{$prefix}--#{$key}\:col-span-#{$i};
  }

  :host(#{$grid-component})
    ::slotted(#{$prefix}-column[#{$key}*='start:#{$i}']) {
    @extend .#{$prefix}--#{$key}\:col-start-#{$i};
  }

  :host(#{$grid-component})
    ::slotted(#{$prefix}-column[#{$key}*='end:#{$i + 1}']) {
    @extend .#{$prefix}--#{$key}\:col-end-#{$i + 1};
  }

  // span 0
  :host(#{$grid-component}) ::slotted(#{$prefix}-column[#{$key}='0']),
  :host(#{$grid-component})
    ::slotted(#{$prefix}-column[#{$key}*='span:0']) {
    @extend .#{$prefix}--#{$key}\:col-span-0;
  }

  // percent after others otherwise span:2 beats span:25%
  @for $p from 1 through 4 {
    $percent: $p * 25;

    :host(#{$grid-component})
      ::slotted(#{$prefix}-column[#{$key}='#{$percent}%']),
    :host(#{$grid-component})
      ::slotted(#{$prefix}-column[#{$key}*='span:#{$percent}%']) {
      @extend .#{$prefix}--#{$key}\:col-span-#{$percent};
    }
  }
}

@if (config.$use-akamai-cdn) {
  $name: -get-akamai-filename($-akamai-filenames, $name, 'name');
  $filename: -get-akamai-filename($-akamai-filenames, $name, 'filename');

  // Special case for weight = Regular (400)
  @if $weight ==Regular {
    @if $style ==italic {
      $filename: '#{$filename}-Italic';
    } @else {
      $filename: '#{$filename}-Regular';
    }
  } @else {
    // Otherwise add weight + optional style (italic)
    $filename: '#{$filename}-#{$weight}';

    @if $style ==italic {
      $filename: '#{$filename}Italic';
    }
  }

  $filenames: ();

  @each $format in $formats {
    $url: 'https://1.www.s81c.com/common/carbon/plex/fonts/#{$name}';

    @if $unicode-range {
      $url: 'https://1.www.s81c.com/common/carbon/plex/fonts/#{$name}/fonts/split/#{$format}/#{$filename}-#{$unicode-range}';
    } @else {
      $url: 'https://1.www.s81c.com/common/carbon/plex/fonts/#{$name}/fonts/complete/#{$format}/#{$filename}';
    }

    // Add extension
    $url: '#{$url}.#{$format}';
    $filenames: list.append(
      $filenames,
      url('#{$url}') format('#{$format}'),
      $separator: comma
    );
  }

  @return $filenames;
}

